import subprocess
import sys

def backup_directory(directory_path, format):
    if format == 'tar.gz':
        command = ['tar', '-czf', f'{directory_path}.tar.gz', directory_path]
    elif format == 'tar.bz2':
        command = ['tar', '-cjf', f'{directory_path}.tar.bz2', directory_path]
    elif format == 'zip':
        command = ['zip', '-r', f'{directory_path}.zip', directory_path]
    elif format == '7z':
        command = ['7z', 'a', f'{directory_path}.7z', directory_path]
    else:
        print("Unsupported compression format")
        sys.exit(1)

    try:
        subprocess.run(command, check=True)
        print(f"Backup created successfully: {directory_path}.{format}")
    except subprocess.CalledProcessError as e:
        print(f"Error creating backup: {e}")

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <format>")
        sys.exit(1)

    directory_path = sys.argv[1]
    format = sys.argv[2]

    backup_directory(directory_path, format)